/* Orchestrator minimal example (Node-style pseudocode) */
async function placeOrder(ctx){
  const id = ctx.tx;
  try{
    await httpPost('http://orders/create',{id,items});
    await httpPost('http://payment/charge',{id,card});
    await httpPost('http://inventory/reserve',{id,items});
    return {status:'OK'};
  }catch(err){
    await httpPost('http://inventory/release',{id}).catch(()=>{});
    await httpPost('http://payment/refund',{id}).catch(()=>{});
    await httpPost('http://orders/cancel',{id}).catch(()=>{});
    return {status:'FAILED',err:err.message};
  }
}
